// ══════════════════════════════════════════════
// CreatorIQ — Load Creator Health Data
// In production: read from audience_health_trend.csv or database
// For POC: uses representative synthetic data from our dataset
// ══════════════════════════════════════════════

const creators = [
  { creator_id: 'C001', name: 'FitWithSarah',    niche: 'Health & Fitness', platform: 'instagram', followers: 85000,  health_score: 38, engagement_rate: 1.8, watch_time_pct: 22, unsubscribe_rate: 3.2, weekly_follower_change: -420 },
  { creator_id: 'C002', name: 'FinanceWithAlex', niche: 'Finance',           platform: 'youtube',   followers: 220000, health_score: 72, engagement_rate: 5.1, watch_time_pct: 58, unsubscribe_rate: 0.4, weekly_follower_change: 1200 },
  { creator_id: 'C003', name: 'TechTalkMia',     niche: 'Tech & Gaming',    platform: 'youtube',   followers: 145000, health_score: 51, engagement_rate: 3.2, watch_time_pct: 41, unsubscribe_rate: 1.8, weekly_follower_change: -180 },
  { creator_id: 'C004', name: 'CookWithJamie',   niche: 'Food & Cooking',   platform: 'tiktok',    followers: 320000, health_score: 81, engagement_rate: 7.4, watch_time_pct: 72, unsubscribe_rate: 0.2, weekly_follower_change: 3400 },
  { creator_id: 'C005', name: 'StyleByLuna',     niche: 'Beauty & Fashion', platform: 'instagram', followers: 67000,  health_score: 44, engagement_rate: 2.1, watch_time_pct: 31, unsubscribe_rate: 2.6, weekly_follower_change: -290 }
];

// Calculate risk level from health score (matches CreatorIQ dataset logic)
function getRiskLevel(score) {
  if (score < 40) return 'Critical';
  if (score < 55) return 'Alert';
  if (score < 70) return 'Watch';
  return 'Safe';
}

// Calculate trend from weekly follower change
function getTrend(change) {
  if (change < -300) return '⬇️ Declining Fast';
  if (change < 0)    return '↘️ Declining';
  if (change < 500)  return '➡️ Stable';
  return '⬆️ Growing';
}

return creators.map(c => ({
  json: {
    ...c,
    risk_level:  getRiskLevel(c.health_score),
    trend:       getTrend(c.weekly_follower_change),
    week_ending: new Date().toISOString().split('T')[0],
    revenue_at_risk_usd: c.health_score < 55 ? Math.round(c.followers * 0.012 * 12) : 0
  }
}));

// ════════════════════════════════════════════
// CreatorIQ — Build Weekly Health Report
// Aggregates all creator alerts into a single report
// ════════════════════════════════════════════

const all = $input.all();
const urgent   = all.filter(i => i.json.alert_type === 'URGENT');
const summaries = all.filter(i => i.json.alert_type === 'WEEKLY_SUMMARY');
const totalRevenueAtRisk = urgent.reduce((sum, i) => sum + (i.json.creator_data?.revenue_at_risk_usd || 0), 0);

const report = {
  report_type:  'CreatorIQ Weekly Audience Health Report',
  week_ending:  new Date().toISOString().split('T')[0],
  generated_at: new Date().toISOString(),
  opportunity:  'O2 — Audience Churn Early Warning ($15K-$40K/year protected)',

  summary: {
    total_creators_monitored: all.length,
    urgent_alerts:            urgent.length,
    healthy_creators:         summaries.length,
    total_revenue_at_risk:    `$${totalRevenueAtRisk.toLocaleString()}/year`,
    action_required:          urgent.length > 0
  },

  urgent_alerts: urgent.map(i => ({
    creator:          i.json.creator_data?.name,
    health_score:     i.json.creator_data?.health_score,
    risk_level:       i.json.creator_data?.risk_level,
    trend:            i.json.creator_data?.trend,
    revenue_at_risk:  `$${(i.json.creator_data?.revenue_at_risk_usd || 0).toLocaleString()}/year`,
    subject:          i.json.subject,
    actions:          i.json.action_needed
  })),

  healthy_creators: summaries.map(i => ({
    creator:      i.json.creator_data?.name,
    health_score: i.json.creator_data?.health_score,
    risk_level:   i.json.creator_data?.risk_level,
    trend:        i.json.creator_data?.trend
  }))
};

return [{ json: report }];
